/* E14: Local minimal DOMPurify stub. Provides a strict allowlist sanitizer
   that strips ALL HTML tags by default and returns the textContent only.
   This is intentionally conservative — the codebase currently does not
   assign untrusted HTML via innerHTML (the only use is the standard
   escape-via-textContent pattern in index.html `esc()`).

   To upgrade to full DOMPurify, replace this file with the upstream
   release from https://github.com/cure53/DOMPurify (apply SRI hash in
   the <script> tag). The build pipeline must verify the checksum. */
(function (root) {
  'use strict';
  function sanitize(input) {
    if (input == null) return '';
    var d = document.createElement('div');
    d.textContent = String(input);
    return d.innerHTML;
  }
  var DOMPurify = { sanitize: sanitize, version: 'milnet-stub-1' };
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = DOMPurify;
  } else {
    root.DOMPurify = DOMPurify;
  }
})(typeof window !== 'undefined' ? window : this);
